  wxPoint srcPt = wxPoint(srcPtX,srcPtY);
  ERL_NIF_TERM lstHead, lstTail;
  lstTail = argv[5];
  if(!enif_is_list(env, lstTail)) Badarg(634,"Options");
  const ERL_NIF_TERM *tpl;
