// wxTreeCtrl::InsertItem
void wxTreeCtrl_InsertItem(WxeApp *app, wxeCommand& Ecmd)
{
  int image=-1;
  int selImage=-1;
  wxETreeItemData * data= NULL;
  wxeMemEnv *memenv = Ecmd.memenv;
  ErlNifEnv *env = Ecmd.env;
  ERL_NIF_TERM * argv = Ecmd.args;
  wxTreeCtrl *This;
  This = (wxTreeCtrl *) memenv->getPtr(env, argv[0], "This");
  ErlNifUInt64 parent_tmp;
  if(!enif_get_uint64(env, argv[1], &parent_tmp)) Badarg(2067,"parent");
  wxTreeItemId parent = wxTreeItemId((void *) (wxUint64) parent_tmp);
  int pos;
  if(!enif_get_int(env, argv[2], &pos)) Badarg(2067,"pos"); // "size_t"
  ErlNifBinary text_bin;
  wxString text;
  if(!enif_inspect_binary(env, argv[3], &text_bin)) Badarg(2067,"text");
  text = wxString(text_bin.data, wxConvUTF8, text_bin.size);
  ERL_NIF_TERM lstHead, lstTail;
  lstTail = argv[4];
  if(!enif_is_list(env, lstTail)) Badarg(2067,"Options");
  const ERL_NIF_TERM *tpl;
  int tpl_sz;
  while(!enif_is_empty_list(env, lstTail)) {
    if(!enif_get_list_cell(env, lstTail, &lstHead, &lstTail)) Badarg(2067,"Options");
    if(!enif_get_tuple(env, lstHead, &tpl_sz, &tpl) || tpl_sz != 2) Badarg(2067,"Options");
    if(enif_is_identical(tpl[0], enif_make_atom(env, "image"))) {
  if(!enif_get_int(env, tpl[1], &image)) Badarg(2067,"image"); // int
    } else     if(enif_is_identical(tpl[0], enif_make_atom(env, "selImage"))) {
  if(!enif_get_int(env, tpl[1], &selImage)) Badarg(2067,"selImage"); // int
    } else     if(enif_is_identical(tpl[0], enif_make_atom(env, "data"))) {
  data = new wxETreeItemData(tpl[1]);
    } else        Badarg(2067,"Options");
  };
  if(!This) throw wxe_badarg("This");
  wxTreeItemId Result = This->InsertItem(parent,pos,text,image,selImage,data);
  wxeReturn rt = wxeReturn(memenv, Ecmd.caller, true);
  rt.send(  rt.make((wxUIntPtr *) Result.m_pItem));

}

