// utils::wxBeginBusyCursor
void utils_wxBeginBusyCursor(WxeApp *app, wxeCommand& Ecmd)
{
  const wxCursor * cursor=wxHOURGLASS_CURSOR;
  wxeMemEnv *memenv = Ecmd.memenv;
  ErlNifEnv *env = Ecmd.env;
  ERL_NIF_TERM * argv = Ecmd.args;
  ERL_NIF_TERM lstHead, lstTail;
  lstTail = argv[0];
  if(!enif_is_list(env, lstTail)) Badarg(2947,"Options");
  const ERL_NIF_TERM *tpl;
  int tpl_sz;
  while(!enif_is_empty_list(env, lstTail)) {
    if(!enif_get_list_cell(env, lstTail, &lstHead, &lstTail)) Badarg(2947,"Options");
    if(!enif_get_tuple(env, lstHead, &tpl_sz, &tpl) || tpl_sz != 2) Badarg(2947,"Options");
    if(enif_is_identical(tpl[0], enif_make_atom(env, "cursor"))) {
  cursor = (wxCursor *) memenv->getPtr(env, tpl[1], "cursor");
    } else        Badarg(2947,"Options");
  };
  ::wxBeginBusyCursor(cursor);

}

